      function
      | SMALLINT -> "SMALLINT"
      | INTEGER -> "INTEGER"
      | BIGINT -> "BIGINT"
      | DECIMAL -> "DECIMAL"
      | REAL -> "REAL"
      | DOUBLE_PRECISION -> "DOUBLE_PRECISION"
      | BOOLEAN -> "BOOLEAN"
      | CHAR -> "CHAR"
      | VARCHAR -> "VARCHAR"
      | DATE -> "DATE"
      | TIMESTAMP -> "TIMESTAMP"
      | TIMESTAMPTZ -> "TIMESTAMPTZ"
      | TIME -> "TIME"
      | TIMETZ -> "TIMETZ"
      | VARBYTE -> "VARBYTE"
      | BINARY -> "BINARY"
      | BYTE -> "BYTE"
      | CHARACTER -> "CHARACTER"
      | DOUBLE -> "DOUBLE"
      | FLOAT -> "FLOAT"
      | INT -> "INT"
      | LONG -> "LONG"
      | NUMERIC -> "NUMERIC"
      | SHORT -> "SHORT"
      | STRING -> "STRING"
      | TIMESTAMP_LTZ -> "TIMESTAMP_LTZ"
